module RefModule(
    input_0,input_1,choose_bit,next
    );parameter width = 32;
    input wire[width-1:0] input_0;
    input wire[width-1:0] input_1;
    input wire choose_bit;
    output reg[width-1:0] next;
  wire [31:0] _tap_input_0 = input_0 & {32{1'b1}};

 always @(*) begin 
    if(choose_bit == 1)
    begin
         next = input_1;
    end
    else 
    begin
         next = input_0;
    end   
end

endmodule
